css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
   width: 70px;
   height: 70px;
   background: var(--loader-color, #4f46e5);
   border-radius: 50px;
   -webkit-mask: radial-gradient(circle 31px at 50% calc(100% + 13px),currentColor 95%,#0000) top 4px left 50%, radial-gradient(circle 31px,currentColor 95%,#0000) center, radial-gradient(circle 31px at 50% -13px,currentColor 95%,#0000) bottom 4px left 50%, linear-gradient(currentColor 0 0);
   -webkit-mask-composite:xor;
   mask-composite:exclude;
   -webkit-mask-repeat:no-repeat;
   animation: l10 1.5s infinite;
}
@keyframes l10  {
  0% {-webkit-mask-size:0 18px,0 18px,0 18px,auto}
16.67%{-webkit-mask-size:100% 18px,0 18px,0 18px,auto}
33.33%{-webkit-mask-size:100% 18px,100% 18px,0 18px,auto}
50% {-webkit-mask-size:100% 18px,100% 18px,100% 18px,auto}
66.67%{-webkit-mask-size:0 18px,100% 18px,100% 18px,auto}
83.33%{-webkit-mask-size:0 18px,0 18px,100% 18px,auto}
100% {-webkit-mask-size:0 18px,0 18px,0 18px,auto}
}
